(function(){
window.bootstrap={};
bootstrap.Modal=class{constructor(el){this.el=el;el.__modalInstance=this;}show(){this.el.classList.add('show');}hide(){this.el.classList.remove('show');}}
bootstrap.Modal.getInstance=function(el){return el.__modalInstance||null;};
document.addEventListener('click',e=>{
  const t=e.target.closest('[data-bs-toggle="modal"]');
  if(t){const sel=t.getAttribute('data-bs-target');const m=document.querySelector(sel);if(m){new bootstrap.Modal(m);m.classList.add('show');}}
  const d=e.target.closest('[data-bs-dismiss="modal"]');
  if(d){const m=d.closest('.modal');if(m&&m.__modalInstance)m.__modalInstance.hide();}
  const tab=e.target.closest('[data-bs-toggle="tab"]');
  if(tab){e.preventDefault();const sel=tab.getAttribute('data-bs-target');const pane=document.querySelector(sel);if(!pane)return;const container=pane.parentElement;container.querySelectorAll('.tab-pane').forEach(p=>p.classList.remove('show','active'));pane.classList.add('show','active');const nav=tab.closest('.nav');if(nav)nav.querySelectorAll('.nav-link').forEach(l=>l.classList.remove('active'));tab.classList.add('active');}
});
})();
